import{_ as l,o as i,c as a,ae as o}from"./chunks/framework.wE_VpzFx.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"note/我的项目/回答/ai.md","filePath":"note/我的项目/回答/ai.md"}'),t={name:"note/我的项目/回答/ai.md"};function r(s,e,n,d,p,c){return i(),a("div",null,[...e[0]||(e[0]=[o('<h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><p>&quot;基于Claude Code搭建了从需求拆解、编码、测试到Code Review的AI辅助工作流，团队整体交付效率提升100%”</p><p>再加几个和 AI 相关的技能就可以，比如说：</p><ol><li>使用 Skill 提升你们的测试覆盖率</li><li>进行 v2 到 v3 的一个升级</li><li>进行 code review</li></ol><p>Code review 可以往前边写一些，然后再写一些掌握的 AI 技能。</p><p>比如：</p><ol><li>Skills</li><li>Agents.md</li><li>如何正确并且高效地创建 plan</li></ol><p>把这些都写在技能里边</p><p>前端有一些工具函数（比如日期函数，还有像 Lodash 那样的一些工具函数），这些都可以做很好的单测，而且覆盖率要求会比较高，基本上每个都要覆盖到。</p><p>然后是组件测试。这种测试主要是针对 Vue 组件，看它是否正确渲染、每个分支是否覆盖。这部分目前写得比较少。</p><p>还有一个是端对端（E2E）测试，可以针对重点逻辑和重点流程来做。</p><p>我觉得测试重点应该是“抓两头”：</p><ol><li>工具函数：需要全部覆盖</li><li>端对端测试：覆盖重要流程</li></ol><p>对于中间的那些组件，我觉得能写就写吧。</p><p>面试的时候就看你怎么说，你也可以说：你在早期先把它（项目）的工具函数以及所有的重要流程都做了端到端测试，然后再重构成 Vue3；发现所有端到端测试都通过后，再手动测试一下其他组件和页面，接着交给测试或者其他同事去测一下。没有问题的话，最后就验收通过。</p><p>面试官有可能会对这个环节提问，你可以找一个小项目提前做下准备。</p><h2 id="ai-简历描述" tabindex="-1">AI 简历描述 <a class="header-anchor" href="#ai-简历描述" aria-label="Permalink to &quot;AI 简历描述&quot;">​</a></h2><p>你是一名资深的前端工程师，现在我在日常开发中用ai做了以下几件事，要求你把它用合适的语言整理出来，可以直接放在简历上成为亮点：</p><ol><li>使用 Opus 4.6 做需求规划，利用头脑风暴（Brainstorm） skill 进行需求规划，该技能会逐条确认需求细节，生成一部分确认一部分，从而大幅提升生成内容与需求的匹配度</li><li>使用做 GPT 5.4 辅助编码, 使用 vue 相关 skill 实现 vue 最佳实践</li><li>使用 vercel-labs/skills 做 skills 管理</li><li>使用 <code>AGENT.md</code> 明确项目的启动、打包流程及内部组件库文档路径，确保 AI 能准确读取项目上下文，AGENTS.md 包含以下内容：</li></ol><ul><li>项目注意点</li><li>内部库的文档</li><li>项目安装流程</li><li>运行流程</li><li>打包流程</li></ul><ol start="5"><li>内部库文档打包：借鉴 Next.js 的做法，建议将组件库文档打包进 <code>dist/docs</code> 目录，并在 <code>agent.md</code> 中指引 AI 读取，避免 AI 使用过期 API。</li><li>接入 CodeRabbit 到 gitlab 中进行 Code Review，自动审查 PR 并提供修复提示词。</li></ol><h2 id="需求规划" tabindex="-1">需求规划 <a class="header-anchor" href="#需求规划" aria-label="Permalink to &quot;需求规划&quot;">​</a></h2><ul><li>头脑风暴（Brainstorm） skill：<a href="https://github.com/obra/superpowers/blob/main/skills/brainstorming/SKILL.md" target="_blank" rel="noreferrer">https://github.com/obra/superpowers/blob/main/skills/brainstorming/SKILL.md</a></li></ul><h2 id="skills-管理" tabindex="-1">skills 管理 <a class="header-anchor" href="#skills-管理" aria-label="Permalink to &quot;skills 管理&quot;">​</a></h2><p><a href="https://github.com/vercel-labs/skills" target="_blank" rel="noreferrer">https://github.com/vercel-labs/skills</a></p><ul><li>全局级 Skill: <code>~/.agents/skills</code></li><li>项目级 Skill: 每个项目根目录下</li></ul><p>使用 <code>skills</code> 命令行工具（类似 pnpm）管理 Skill，支持全局安装（如 Vue 最佳实践）与项目级安装（如文档同步），避免重复下载。</p><ul><li>hyf0/vue-skills@vue-testing-best-practices：vue 单元测试</li><li>antfu/skills</li><li>Brainstorm Skill</li></ul><h2 id="agent-配置" tabindex="-1">Agent 配置 <a class="header-anchor" href="#agent-配置" aria-label="Permalink to &quot;Agent 配置&quot;">​</a></h2><p>Agent 配置文件规范：建议在项目中配置 <code>agent.md</code>，明确项目的启动、打包流程及内部组件库文档路径，确保 AI 能准确读取项目上下文。</p><p>AGENTS.md 内容：</p><ul><li>项目注意点</li><li>内部库的文档</li><li>项目安装流程</li><li>运行流程</li><li>打包流程</li></ul><p>内部库文档打包：借鉴 Next.js 的做法，建议将组件库文档打包进 <code>dist/docs</code> 目录，并在 <code>agent.md</code> 中指引 AI 读取，避免 AI 使用过期 API。</p><p>二、高级概念与技术栈探讨</p><ol><li>Harness 工程与自动化 Harness Engineering（工程）：这是一种让 AI 接管整个开发流程的模式，通过多 Agent 协作（如 GPT-4 调研 + GPT-5 编码）和自动化测试，实现长达数小时的无人值守开发。 成本与门槛：该模式极度消耗 Token（约 $100-$200/天），且需顶级模型支持，目前主要在开源社区验证，个人实践成本过高。 模型选型策略：讨论了不同模型的适用场景，建议复杂规划使用 Claude Sonnet 或 GPT-4，编码实现使用 GPT-5 或 Claude Haiku，以平衡成本与效果。</li><li>代码审查与 CI/CD 集成 Code Review 工具推荐：CodeRabbit 工具能集成到 GitLab，自动审查 PR 并提供修复提示词，可以研究下如何在私有化部署的 GitLab 中配置。</li></ol><p>CodeRabbit: <a href="https://www.coderabbit.ai/" target="_blank" rel="noreferrer">https://www.coderabbit.ai/</a> 各个模型特点：<a href="https://ampcode.com/models" target="_blank" rel="noreferrer">https://ampcode.com/models</a></p><h2 id="code-review" tabindex="-1">code review <a class="header-anchor" href="#code-review" aria-label="Permalink to &quot;code review&quot;">​</a></h2><p>提示词给cursor</p><h2 id="和ai的一种新协作方式-harness-engineering" tabindex="-1">和AI的一种新协作方式 Harness engineering <a class="header-anchor" href="#和ai的一种新协作方式-harness-engineering" aria-label="Permalink to &quot;和AI的一种新协作方式 Harness engineering&quot;">​</a></h2><ul><li>skill 统筹/编排器</li></ul><p>使用顶级模型</p><ul><li>GPT 5.4：调研</li><li>Opus 4.6: 任务不太清楚，</li><li>sonnet 4.6</li></ul><p>顶级模型做规划 高级模型做编码</p>',43)])])}const b=l(t,[["render",r]]);export{u as __pageData,b as default};
